import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';

export default function Counter() {
  let count = 0;
  const increment = () => {
    count = count + 1;
    console.log(count);
  };
  return (
    <View>
      <Text>Count: {count}</Text>
      <Button title="Press" onPress={increment} />
    </View>
  );
}

